import { describe, it, expect } from "vitest";
import { processScenario } from "./process-scenario.js";

function scenario(customer: { yearsWithMHPCO: number }, steps: any[]) {
  return { customer, steps };
}

describe("Claim Office", () => {
  it.todo("should return premium of 5 G for empty item list (only processing fee)");

  it.todo("should return premium 115 G for single plain sword (100 base + 10 first insurance + 5 fee)");
  it.todo("should return premium 71 G for single plain amulet (60 base + 6 first insurance + 5 fee)");
  it.todo("should return premium 93 G for single plain staff (80 base + 8 first insurance + 5 fee)");
  it.todo("should return premium 49 G for single plain potion (40 base + 4 first insurance + 5 fee)");
  it.todo("should return premium 33 G for single rune (25 base + 2.5 first insurance + 5 fee = 32.5 rounded up)");

  it.todo("should add 50% cursed surcharge to cursed sword — newcomer: 165 G (100 base + 50 curse + 10 first insurance + 5 fee)");

  it.todo("should add 30% high-enchantment surcharge for enchantment ≥ 5 — sword enchantment 5: 145 G (100 base + 30 high-ench + 10 first insurance + 5 fee)");
  it.todo("should NOT add high-enchantment surcharge for enchantment 4 — plain sword: 115 G (100 base + 10 first insurance + 5 fee)");
  it.todo("should apply both cursed and high-enchantment surcharges — cursed sword enchantment 5: 195 G (100 base + 50 curse + 30 high-ench + 10 first insurance + 5 fee)");

  it.todo("should apply 20% loyalty discount for customer with ≥ 2 years — plain sword, 2 years, first quote: 95 G (100 base - 20 loyalty + 10 first insurance + 5 fee)");
  it.todo("should apply loyalty discount at exactly 2 years threshold — plain sword, exactly 2 years: 95 G");

  it.todo("should apply 15% follow-up contract discount on second quote — two sequential sword quotes: first 115 G, second 100 G (100 base + 10 first insurance - 15 follow-up + 5 fee)");
  it.todo("should apply follow-up contract discount from second quote onward — three sequential sword quotes, third gets discount");

  it.todo("should apply first insurance surcharge to every item even on follow-up contract — from integration example spec clarification");

  it.todo("should apply all modifiers combined — long-standing customer (3 yrs) second contract, cursed sword enchantment 7: 160 G (100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first-ins - 15 follow-up + 5 fee)");

  it.todo("should compute base premium 50 G for 2 runes (2 × 25, no block)");
  it.todo("should compute base premium 60 G for 3 runes (block applies)");
  it.todo("should compute base premium 100 G for 4 runes (4 × 25, no block — block requires exactly 3)");
  it.todo("should compute base premium 175 G for 7 runes (7 × 25, no block)");

  it.todo("should treat runes and moonstones as different component types — 2 runes + 1 moonstone: 75 G base (3 × 25, no block)");
  it.todo("should form separate blocks for each component type — 3 runes + 3 moonstones: 120 G base (60 + 60, two blocks)");

  it.todo("should apply cursed surcharge only to the cursed item, not policy total — cursed sword + plain amulet: policy base 160 G, curse adds 50 G → 210 G before further modifiers");
  it.todo("should apply item-specific modifiers to each item separately — cursed sword + highly enchanted amulet");

  it.todo("should compute insurance sum for two swords: 2000 G (2 × 1000), cap 4000 G");
  it.todo("should compute insurance sum for sword + amulet: 1600 G (1000 + 600), cap 3200 G");
  it.todo("should compute insurance sum for sword + 3 runes (block): 1750 G (1000 + 3×250); block discount affects premium only, not insurance sum");

  it.todo("should pay 400 G for standard sword (steel, enchantment 3) damage 500 G — 500 - 100 deductible = 400 G");
  it.todo("should pay 100 G for rune damage 200 G — 200 - 100 deductible = 100 G (runes have no enchantment or material)");

  it.todo("should apply 100 G deductible per damaged item — dragon attack damages sword (500 G) and amulet (300 G): payout 600 G ((500-100)+(300-100))");

  it.todo("should reimburse at 50% for enchantment ≥ 8 — dragon-material sword enchantment 8, damage 1000 G: 50% of 1000 = 500, then -100 deductible = 400 G");
  it.todo("should fully reimburse dragon material — dragon-material sword enchantment 5, damage 800 G: 800 - 100 deductible = 700 G");
  it.todo("should apply 50% rule when both clauses applicable — dragon-material sword enchantment 9, damage 1000 G: 50% of 1000 = 500, then -100 deductible = 400 G (50% rule wins over dragon material)");
  it.todo("should apply only high-enchantment clause for non-dragon material — steel sword enchantment 9, damage 1000 G: 50% of 1000 = 500, then -100 deductible = 400 G");

  it.todo("should treat each damage entry as separate damage with own deductible — two swords damaged by dragon attack");

  it.todo("should reject claim if damage count exceeds insured count — 2 sword damages but only 1 sword insured → non-zero exit");
  it.todo("should reject claim with unknown item type in quote → non-zero exit, error to stderr");
  it.todo("should reject claim with item not in policy → non-zero exit, error to stderr");
  it.todo("should reject claim with negative damage amount → non-zero exit, error to stderr");

  it.todo("should cap total payout at 2× insurance sum — first claim 1500 G on 1000 G sword: payout 1400 G, remainingCap 600 G");
  it.todo("should reduce second claim to remaining cap — second claim 1500 G on same policy: payout 600 G, remainingCap 0 G");
  it.todo("should exhaust cap completely across claims — verify cap goes to 0 after sufficient claims");

  it.todo("should round premium up in MHPCO's favor — premium 197.5 G → 198 G");
  it.todo("should round payout down in MHPCO's favor — payout 350.5 G → 350 G");
  it.todo("should keep intermediate amounts as fractions, round only final result");

  it.todo("should process full schema example — quote amulet then claim: premium 71 G, payout 100 G (200-100), remainingCap 1100 G (2×600=1200, 1200-100)");

  it.todo("should compute capped payout for claim beyond insurance value — capped by remaining cap");
});

