it("should return premium of 5 G for empty item list (only processing fee)", () => {
    const input = scenario({ yearsWithMHPCO: 0 }, [{ op: "quote", items: [] }]);
    const result = processScenario(input);
    expect(result.results[0]).toEqual({ premium: 5 });
  });

