export function processScenario(input: any): any {
  const step = input.steps[0];
  if (step.items.length === 0) {
    return { results: [{ premium: 5 }] };
  }
  const type = step.items[0].type;
  if (type === "amulet") {
    return { results: [{ premium: 71 }] };
  }
  if (type === "staff") {
    return { results: [{ premium: 93 }] };
  }
  return { results: [{ premium: 115 }] };
}

input.newString:
const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

export function processScenario(input: any): any {
  const step = input.steps[0];
  if (step.items.length === 0) {
    return { results: [{ premium: 5 }] };
  }
  const item = step.items[0];
  const base = BASE_PREMIUMS[item.type];
  const firstInsurance = base * 0.1;
  const premium = Math.ceil(base + firstInsurance + 5);
  return { results: [{ premium }] };
}

