const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function computeQuotePremium(items: any[], customer: any, quoteIndex: number): number {
  if (items.length === 0) return 5;

  const item = items[0];
  const base = BASE_PREMIUMS[item.type];
  let total = base;

  if (item.cursed) total += base * 0.5;
  if (item.enchantment >= 5) total += base * 0.3;
  total += base * 0.1; // first insurance

  if (customer.yearsWithMHPCO >= 2) total -= base * 0.2; // loyalty
  if (quoteIndex > 0) total -= base * 0.15; // follow-up contract

  return Math.ceil(total + 5);
}

export function processScenario(input: any): any {
  const results: any[] = [];
  let quoteIndex = 0;

  for (const step of input.steps) {
    if (step.op === "quote") {
      const premium = computeQuotePremium(step.items, input.customer, quoteIndex);
      results.push({ premium });
      quoteIndex++;
    }
  }

  return { results };
}

